import React from 'react'

function Hotel({trip}) {
  return (
    <div className='text-black flex justify-center items-center text-lg mt-10'>
         <div >
            <h2 className='text-3xl font-semibold'> Hotel Recommendation</h2>
         </div>

       <div>
           {
             trip?.Hotel
           }
       </div>
      
    </div>
  )
}

export default Hotel
